class Solution {
    public int leastOpsExpressTarget(int x, int target) {
        int ans = 0;
        while (target > 0) {
            if (target % x == 0) {
                ans += target / x - 1;
                target = 1;
            } else if (target < x) {
                break;
            } else {
                int p = target / x;
                if (p * x - target < target - (p - 1) * x) {
                    ans += p;
                    target = target - p * x;
                } else {
                    ans += p - 1;
                    target = (p - 1) * x - target;
                }
            }
        }
        return ans + target;
    }
}
